import React from 'react';
import { withStyles} from '@material-ui/core/styles';
import TableRow from '@material-ui/core/TableRow';
import TableCell from '@material-ui/core/TableCell';



const StyledTableCell = withStyles(theme => ({

    head: {
        backgroundColor: '#00823c',
        color: theme.palette.common.white,
        fontWeight: 600,
    },
    body: {
        fontSize: 14,
    },
}))(TableCell);

const StyledTableRow = withStyles(theme => ({
    root: {
        '&:nth-of-type(odd)': {
            backgroundColor: '#f1f5dc',
        },
        '&:nth-of-type(even)': {
            backgroundColor: '#c5dfb8',
        },
    },
}))(TableRow);


const CalcTable = (props)=>{
    let calc =props.calc;
    
    return(
        <>
            {calc.map((calc)=>(
            
                <StyledTableRow>
                    {calc.map((complex, i) => (
                        i === 0 ? <StyledTableCell align="left">{complex}</StyledTableCell> : <StyledTableCell align="right">{complex}</StyledTableCell>

                    ))}
                </StyledTableRow>
        
            ))}
        </>
            
    )
};
export default CalcTable;