import React from 'react';
import Button from '@material-ui/core/Button';
import TextField from '@material-ui/core/TextField';
import FormControl from '@material-ui/core/FormControl';
import FormControlLabel from '@material-ui/core/FormControlLabel';
import Checkbox from '@material-ui/core/Checkbox';


const CalculateField=(props)=>{
    const err=props.err;
    const check=props.check
    const checkB = props.checkB
    const periods=props.periods
    const label=props.label;
    const order=props.order1;
    return(
        <FormControl  noValidate autoComplete="off">
            <TextField id={`outlined-basic${props.id}`}
                error={err}
                label={label}
                variant="outlined"
                onChange={props.onChange} />
            

            <FormControlLabel
                control={<Checkbox checked={check.period1} onChange={checkB} name="period1"  />}
                label={periods.period1}
            />
            <FormControlLabel
                control={<Checkbox checked={check.period2} onChange={checkB} name="period2" />}
                label={periods.period2}
            />
            <FormControlLabel
                control={<Checkbox checked={check.period3} onChange={checkB} name="period3" />}
                label={periods.period3}
            />
            
            <Button size="large" className={order} variant="contained" color="secondary" onClick={props.onClick}>Розрахувати</Button>
        </FormControl >
    )
}
export default CalculateField;