import React from 'react';
import Typography from '@material-ui/core/Typography';
import { makeStyles } from '@material-ui/core/styles';
import Paper from '@material-ui/core/Paper';
import Button from '@material-ui/core/Button';
import Grid from '@material-ui/core/Grid';
import List from '@material-ui/core/List';
import ListItem from '@material-ui/core/ListItem';
import ListItemIcon from '@material-ui/core/ListItemIcon';
import ListItemText from '@material-ui/core/ListItemText';

import { ReactComponent as Rect } from '../img/rect.svg';
import listBlock from '../utils/listBlock';
import ModalOrder from './ModalOrder';
import Data from '../data/data.json';

let val = 0;
let payload = {};
const useStyles = makeStyles((theme, props) => ({
    padding:{
        paddingTop:0,
        paddingBottom:0,
    },
    paddingItem: {
        paddingTop: 0,
        paddingBottom: 0,
    },
    root: {
        paddingLeft: '1rem',
    },
    textContainer: {
        padding: '1rem',
    },
    listIcon: {
        minWidth: '19px',
    },
    advTitle: {
        color: '#00823c',
        paddingTop: 0,
        paddingBottom: '8px',
    },
    titleBox: {
        width: 'inherit',
        position: 'relative',
        [theme.breakpoints.up('xs')]: {
            height: '300px',
        },
        [theme.breakpoints.down('xs')]: {
            height: '200px',
        },
    },
    boxPosition: {
        color: '#ffff',
        background: 'rgba(0, 130, 90, 0.7)',
        position: 'absolute',
        bottom: '0rem',
        width: '100%',
        [theme.breakpoints.up('xs')]: {
            display: 'flex',
        },
        [theme.breakpoints.down('xs')]: {
            display: 'block',
        },
    },
    wrapTable: {
        marginBottom: '2rem',
    },
    wrap:{
        paddingBottom:'2rem',
        width: 'inherit',
        marginBottom:'0.5rem',
    },
    order: {
        backgroundColor:'#ffa000',
        color:'#ffffff',
        margin:'0.4rem',
    },
    container: {
        display: 'flex',
    },
    
}));


const ContentSection =(props)=>{
    let calc = [];
    let title = [""];
    const list=[];
    let valBuff = 0

    const [open, setOpen] = React.useState(false);
    const [modal, setModal] = React.useState(0);
    

    
    const handleClose = () => {
        setOpen(false);
    };
    
    
    const data=props.data;
    
    const classes = useStyles();
    const [label, setLabel] = React.useState('Кількість, га');
    const [value, setValue] = React.useState(0);
    const [err,setErr] = React.useState(false);
    const [checked, setChecked] = React.useState(false);
    const [display, setDisplay] = React.useState("none")
    const [displayTable, setDisplayTable] = React.useState("none")
    const [check, setCheck] = React.useState({
        period1: true,
        period2: true,
        period3: true,
    });
    const [valueField, setValueField] = React.useState({});
    //console.log(valueField)
    const handleChangeCheck = (event) => {
        setCheck({ ...check, [event.target.name]: event.target.checked });
    };
    
    const handleChange = event => {
        val = event.target.value;
    };
    const handleSubmit = event =>{
        if (isNaN(val)) {
            setLabel('Помилка');
            setErr(true);
        } else {
            setValue(val);
            setLabel('Кількість, га');
            setErr(false);
            setChecked((prev) => !prev);
            setDisplay(display === 'none' ? '' : 'none')
            setDisplayTable( '' )
            
        }
        
    }
    const handleClickOpen = (e) => {
        const idx = e.currentTarget.id;
        payload = calc;
        setOpen(true);
        setModal(idx);
        let valField = {};
        calc.map((calc)=>{
            valField[calc[0]] = 0;
        })
        setValueField(valField);

    };
    
    const handleChangeCalc = () => {
        setChecked((prev) => !prev);
        setDisplay(display==='none'?'':'none')
    
    };
    listBlock(data, list);
    return(
        <Paper className={classes.wrap} elevation={3} id={`section${data.id}`} >
            <div className={classes.titleBox} style={{ backgroundImage: `url(/static/img/${data.image}.jpg)`}}>
                <div  className={classes.boxPosition}>
                    <div>
                    <Typography variant="h5" className={classes.root}>{data.title}</Typography>
                    <Typography variant="subtitle1" className={classes.root}>{data.subtitle}</Typography>
                    </div>
                    <div style={{ marginLeft: 'auto'}}>
                    <Button size="large" className={classes.order} onClick={handleClickOpen} id={data.id}>
                        Замовити
                    </Button>
                    </div>
                </div>
            </div>
            <Typography vatiant="body1" align="justify" className={classes.textContainer}>{data.desc}</Typography>
            {list.map((list)=>(
                <>
                    
                {list.map((list, i)=>(
                    <>
                {i===0?<Typography variant="h6" className={classes.textContainer + ' ' + classes.advTitle}>{list}</Typography>:
                            < List className={classes.padding}>
                                <ListItem className={classes.paddingItem}>
                                <ListItemIcon className={classes.listIcon}>
                                    <Rect />
                                </ListItemIcon>
                                <ListItemText primary={list} />
                            </ListItem>
                    </List>}
                    </>
                ))}
                
                </>
            ))}
           
            <Grid item xs={12} style={{textAlign:'center'}}>
                <Button  size="large" className={classes.order} onClick={handleClickOpen} id={data.id}>
                Замовити
            </Button>
            </Grid>
            <ModalOrder open={open}
                data={data}
                id={modal}
                onClose={handleClose}
                content={calc}
                value={value}
                check={check}
                title1={data.title}
                title={title}
                value={value}
                calc={calc}
                onClick={handleSubmit}
                onChange={handleChange}
                checkB={handleChangeCheck}
                err={err}
                label={label}
                order={classes.order}
                periods={data.nameperiods}
                id={data.id}
                display={display}
                setDisplay={setDisplay}
                displayTable={displayTable}
                setDisplayTable={setDisplayTable}
                valueField={valueField}
                setValueField = {setValueField}
                valBuff={valBuff}
            />  
        </Paper>
    )
}
export default ContentSection;