import React from 'react';
import Container from '@material-ui/core/Container';
import { makeStyles } from '@material-ui/core/styles';

import { InView } from 'react-intersection-observer';
import Data from '../data/data.json';
import ContentSection from './ContentSection';
import './topmenu.css';

const useStyles = makeStyles((theme) => ({
    root:{
        paddingLeft: '1rem',
    },
    textContainer:{
        padding:'1rem',
    },
    listIcon:{
        minWidth: '19px',
    },
    advTitle:{
        color:'#00823c',
        paddingTop:0,
        paddingBottom:'8px',
    },
    titleBox:{
        width: 'inherit',
        position: 'relative',
    },
    boxPosition:{
        color: '#ffff',
        background: 'rgba(0, 130, 90, 0.7)',
        position: 'absolute',
        bottom: '1rem',
        width: 'inherit',
    },
    wrapTable: {
        marginBottom: '2rem',
    },
    wrap: {
        paddingTop: '7.6rem',
    },
}));


const LandingCard =(props)=>{
    //const [name, setName] = React.useState({});
    //console.log(Data[1].drug)
    //for(let prop in Data[1].drug){
    //    console.log(prop)
    //    setName({ ...name, [prop]: 0 })
    //}
    //
    //console.log(name)
    const classes = useStyles();
    const data=Data[0].crop;
    const valueMenu = props.valueMenu;
    const setValueMenu = props.setValueMenu;
    //console.log('valueMenu', valueMenu);
    const handleSectionActive = (inView, entry) => {
        //console.log('Inview:', inView, 'entry:', entry.target.childNodes[0].id);
        if (inView) {
            setValueMenu((parseInt(entry.target.childNodes[0].id.match(/\d+/))) - 1);
           // console.log('Go to:', entry.target.childNodes[0].id);
        };   
    };
    //console.log('valueMenu',valueMenu);
    return(
        <main>
            <Container  className={classes.wrap}>
                {data.map((data)=>( 
                    <InView as="section" onChange={handleSectionActive}>
                        <ContentSection  
                            data={data}
                            /> 
                    </InView> 
                ))}

            </Container>
        </main>
    );

}
export default LandingCard;