import React from 'react';
import { makeStyles } from '@material-ui/core/styles';
import Toolbar from '@material-ui/core/Toolbar';
import Typography from '@material-ui/core/Typography';
import IconButton from '@material-ui/core/IconButton';
import Menu from '@material-ui/core/Menu';
import MenuItem from '@material-ui/core/MenuItem';

import { ReactComponent as MenuIcon } from '../img/iconMenu.svg';

const useStyles = makeStyles((theme) => ({
    root: {
        flexGrow: 1,
        visibility: 'hidden',
        display:'none',
            [theme.breakpoints.down('xs')]: {
                visibility: 'visible',
                display: 'block',
            },
    },
        colorPrimary: {
           // marginTop: '-3rem',
           // position: 'fixed',
            background: 'linear-gradient(#555, #222)',
            boxShadow: '0 1px 1px #777, 0 1px 0 #666 inset',
        },
    menuButton: {
        marginRight: theme.spacing(2),
    },
    title: {
        flexGrow: 1,
    },
}));

export default function MobileMenu() {
    const [anchorEl, setAnchorEl] = React.useState(null);
    const classes = useStyles();
    const handleClick = (event) => {
        setAnchorEl(event.currentTarget);
    };
    const handleClose = () => {
        setAnchorEl(null);
    };
    const handleScroll = (e) => {
        setAnchorEl(null);
        const idx = e.currentTarget.id;
            const section = (document.getElementById(`section${idx}`).offsetTop)-130;           
            window.scrollTo({
                top: section,
                behavior: "smooth"
            })
    }

    return (
        <div className={classes.root}>
            <div position="static" className={classes.colorPrimary}>
                <Toolbar>
                    <IconButton aria-controls="simple-menu" aria-haspopup="true" onClick={handleClick} edge="start" className={classes.menuButton} color="inherit" aria-label="menu">
                        <MenuIcon />
                    </IconButton>
                    <Menu
                        id="simple-menu"
                        anchorEl={anchorEl}
                        keepMounted
                        open={Boolean(anchorEl)}
                        onClose={handleClose}
                    > 
                        <MenuItem onClick={handleScroll} id="1">Ярі та озимі зернові культури</MenuItem>
                        <MenuItem onClick={handleScroll} id="2">Соняшник</MenuItem>
                        <MenuItem onClick={handleScroll} id="3">Кукурудза</MenuItem>
                        <MenuItem onClick={handleScroll} id="4">Ярий та озимий ріпак</MenuItem>
                        <MenuItem onClick={handleScroll} id="5">Соя</MenuItem>
                        <MenuItem onClick={handleScroll} id="6">Цукровий буряк</MenuItem>
                    </Menu>
                    <Typography variant="h6" className={classes.title}>
                        Меню
                    </Typography>
                   
                </Toolbar>
            </div>
        </div>
    );
}